import React, { useEffect, useState } from "react";
import { useNavigate, useLocation, Link } from "react-router-dom";
import "./Register.css";

function Register() {
  const navigate = useNavigate();
  const location = useLocation();
  const [user, setUser] = useState(null);

  useEffect(() => {
    const params = new URLSearchParams(location.search);
    const tokenFromURL = params.get("token");

    const token = tokenFromURL || localStorage.getItem("auth_token");

    if (!token) {
      setUser(null);
      return;
    }

    try {
      const payload = JSON.parse(atob(token.split(".")[1]));

      localStorage.setItem("auth_token", token);

      // ⚠️ FIXED: consistent id naming
      if (payload._id) localStorage.setItem("userId", payload._id);
      if (payload.mbtiType)
        localStorage.setItem("userType", payload.mbtiType);

      setUser(payload);

      const pending = localStorage.getItem("pendingResult");

      if (pending) {
        fetch("http://localhost:5000/api/user/mbti", {
          method: "PUT",
          headers: {
            "Content-Type": "application/json",
            Authorization: `Bearer ${token}`,
          },
          body: JSON.stringify({ mbtiType: pending }),
        });

        localStorage.removeItem("pendingResult");

        navigate(`/result?type=${pending}`, { replace: true });
        return;
      }

      // ⚠️ FIX: prevent flicker loop
      if (tokenFromURL) {
        navigate("/register", { replace: true });
      }
    } catch (err) {
      console.log("Token decode error", err);
      localStorage.removeItem("auth_token");
    }
  }, [location.search]);

  const handleGoogleLogin = () => {
    if (localStorage.getItem("google_login_started")) return;

    localStorage.setItem("google_login_started", "true");
    window.location.href = "http://localhost:5000/auth/google";
  };

  const userPhoto = user?.photo?.replace("http:", "https:") ||
    "/images/default.png";

  return (
    <div className="register-page">
      <div className="register-card">
        {!user ? (
          <>
            <h2 className="register-title">ავტორიზაცია</h2>

            <p className="register-description">
              გაიარე ავტორიზაცია Google ანგარიშით და შეინახე MBTI შედეგები
            </p>

            <button className="google-signin" onClick={handleGoogleLogin}>
              <img
                src="https://developers.google.com/identity/images/g-logo.png"
                alt="Google"
              />
              Continue with Google
            </button>
          </>
        ) : (
          <div className="register-user-preview">
            <img
              src={userPhoto}
              alt="user"
              className="register-user-photo"
              referrerPolicy="no-referrer"
            />

            <p>მოგესალმებით, {user.name}</p>

            <Link to="/profile" className="google-signin">
              პროფილის ნახვა
            </Link>
          </div>
        )}
      </div>
    </div>
  );
}

export default Register;
